83	#[derive(Debug)]
84	pub struct VadSegmenter {
85	    cfg: VadConfig,
86	    next_utterance_id: u64,
87	    frame_idx: u64,
88	
89	    // rolling buffers (bounded)
90	    preroll: VecDeque<f32>,
91	    pending_silence: VecDeque<f32>,
92	
93	    // state
94	    in_speech: bool,
95	    start_run_frames: usize,
96	    silence_run_frames: usize,
97	
98	    // current utterance under construction
99	    cur_audio: Vec<f32>,
100	    cur_start_frame_idx: u64,
101	    cur_timings: UtteranceTimings,
102	    cur_vad_compute_ms: u64,
103	
104	    // sliding window for Silero scoring (512 samples)
105	    silero_window: [f32; SILERO_WINDOW_SAMPLES],
106	    silero_window_initialized: bool,
107	}
108	
109	impl VadSegmenter {
110	    pub fn new(cfg: VadConfig) -> Self {
111	        let preroll_cap = cfg.preroll_frames * FRAME_SAMPLES;
112	        let pending_cap = cfg.end_silence_frames * FRAME_SAMPLES;
113	        Self {
114	            cfg,
115	            next_utterance_id: 1,
116	            frame_idx: 0,
117	            preroll: VecDeque::with_capacity(preroll_cap),
118	            pending_silence: VecDeque::with_capacity(pending_cap),
119	            in_speech: false,
120	            start_run_frames: 0,
121	            silence_run_frames: 0,
122	            cur_audio: Vec::new(),
123	            cur_start_frame_idx: 0,
124	            cur_timings: UtteranceTimings::new(),
125	            cur_vad_compute_ms: 0,
126	            silero_window: [0.0; SILERO_WINDOW_SAMPLES],
127	            silero_window_initialized: false,
128	        }
129	    }
130	
131	    /// Update the internal 512-sample window using the newest 20ms frame (320 samples).
132	    ///
133	    /// This matches the plan constraint: advance by 320 samples but score on a 512-sample window.
134	    fn update_silero_window(&mut self, frame: &[f32; FRAME_SAMPLES]) {
135	        if !self.silero_window_initialized {
136	            // Start with zero-padded history; place the first frame at the tail.
137	            self.silero_window = [0.0; SILERO_WINDOW_SAMPLES];
138	            let tail_start = SILERO_WINDOW_SAMPLES - FRAME_SAMPLES;
139	            self.silero_window[tail_start..].copy_from_slice(frame);
140	            self.silero_window_initialized = true;
141	            return;
142	        }
143	
144	        // Shift left by 320 (dropping oldest) and append the new frame at the end.
145	        // Remaining overlap = 512 - 320 = 192 samples.
146	        self.silero_window.copy_within(FRAME_SAMPLES.., 0);
147	        let tail_start = SILERO_WINDOW_SAMPLES - FRAME_SAMPLES;
148	        self.silero_window[tail_start..].copy_from_slice(frame);
149	    }
150	
151	    /// Push a 20ms frame and a VAD score (0..1), returning an utterance job when one completes.
152	    ///
153	    /// This method is deterministic and is the basis for unit tests. In production, the score
154	    /// is computed from the current 512-sample Silero window.
155	    pub fn push_scored_frame(
156	        &mut self,
157	        frame: &[f32; FRAME_SAMPLES],
158	        score: f32,
159	    ) -> Option<UtteranceJob> {
160	        self.frame_idx += 1;
161	
162	        // Maintain bounded preroll samples regardless of state.
163	        self.preroll.extend(frame.iter().copied());
164	        let preroll_cap = self.cfg.preroll_frames * FRAME_SAMPLES;
165	        while self.preroll.len() > preroll_cap {
166	            let _ = self.preroll.pop_front();
167	        }
168	
169	        if !self.in_speech {
170	            if score >= self.cfg.start_threshold {
171	                self.start_run_frames += 1;
172	            } else {
173	                self.start_run_frames = 0;
174	            }
175	
176	            if self.start_run_frames >= self.cfg.min_speech_frames {
177	                self.in_speech = true;
178	                self.silence_run_frames = 0;
179	                self.pending_silence.clear();
180	                self.cur_audio.clear();
181	
182	                // Start utterance with preroll (includes the first speech frames already in preroll).
183	                self.cur_audio.extend(self.preroll.iter().copied());
184	                if self.cur_audio.is_empty() {
185	                    // When preroll is disabled, ensure we still capture the triggering frame.
186	                    self.cur_audio.extend(frame.iter().copied());
187	                }
188	                self.cur_start_frame_idx = self
189	                    .frame_idx
190	                    .saturating_sub(self.cfg.preroll_frames as u64);
191	                self.cur_timings = UtteranceTimings::new();
192	                self.cur_vad_compute_ms = 0;
193	            }
194	
195	            return None;
196	        }
197	
198	        // In speech: enforce cap by frames.
199	        let cur_frames = self.cur_audio.len() / FRAME_SAMPLES;
200	        if cur_frames >= self.cfg.max_utterance_frames {
201	            tracing::warn!(
202	                utterance_id = self.next_utterance_id,
203	                max_frames = self.cfg.max_utterance_frames,
204	                "Max utterance length exceeded; force-cutting"
205	            );
206	            return Some(self.finish_current_utterance_with_tail());
207	        }
208	
209	        if score >= self.cfg.stop_threshold {
210	            // Speech (or stable continuation): flush pending silence into the utterance.
211	            self.silence_run_frames = 0;
212	            if !self.pending_silence.is_empty() {
213	                self.cur_audio.extend(self.pending_silence.drain(..));
214	            }
215	            self.cur_audio.extend(frame.iter().copied());
216	            return None;
217	        }
218	
219	        // Potential end-of-speech: buffer silence frames until we confirm end.
220	        self.silence_run_frames += 1;
221	        self.pending_silence.extend(frame.iter().copied());
222	        let pending_cap = self.cfg.end_silence_frames * FRAME_SAMPLES;
223	        while self.pending_silence.len() > pending_cap {
224	            let _ = self.pending_silence.pop_front();
225	        }
226	
227	        if self.silence_run_frames < self.cfg.end_silence_frames {
228	            return None;
229	        }
230	
231	        Some(self.finish_current_utterance_with_tail())
232	    }
233	
234	    fn finish_current_utterance_with_tail(&mut self) -> UtteranceJob {
235	        // Append tail portion (D-07) from the buffered silence.
236	        let tail_samples = self.cfg.tail_frames * FRAME_SAMPLES;
237	        let mut appended = 0usize;
238	        while appended < tail_samples {
239	            match self.pending_silence.pop_front() {
240	                Some(s) => {
241	                    self.cur_audio.push(s);
242	                    appended += 1;
243	                }
244	                None => break,
245	            }
246	        }
247	
248	        let id = self.next_utterance_id;
249	        self.next_utterance_id += 1;
250	
251	        self.cur_timings.vad_ms = self.cur_vad_compute_ms;
252	        let job = UtteranceJob {
253	            utterance_id: id,
254	            audio: std::mem::take(&mut self.cur_audio),
255	            timings: self.cur_timings,
256	            start_frame_idx: self.cur_start_frame_idx,
257	            end_frame_idx: self.frame_idx,
258	        };
259	
260	        // Reset state for next utterance.
261	        self.in_speech = false;
262	        self.start_run_frames = 0;
263	        self.silence_run_frames = 0;
264	        self.pending_silence.clear();
265	        self.preroll.clear();
266	        self.cur_vad_compute_ms = 0;
267	
268	        job
269	    }
270	
271	    /// Score the newest 20ms frame using Silero on a 512-sample sliding window.
272	    pub fn score_with_silero(
273	        &mut self,
274	        model: &mut silero_vad_rust::silero_vad::model::OnnxModel,
275	        frame: &[f32; FRAME_SAMPLES],
276	    ) -> anyhow::Result<f32> {
277	        self.update_silero_window(frame);
278	        let probs = model.forward_chunk(&self.silero_window, SAMPLE_RATE_HZ)?;
279	        Ok(probs[[0, 0]])
280	    }
281	
282	    /// Convenience: update internal window + push the frame using a Silero-derived score.
283	    pub fn push_frame_silero(
284	        &mut self,
285	        model: &mut silero_vad_rust::silero_vad::model::OnnxModel,
286	        frame: &[f32; FRAME_SAMPLES],
287	    ) -> anyhow::Result<Option<UtteranceJob>> {
288	        let was_in_speech = self.in_speech;
289	        let t0 = Instant::now();
290	        let score = self.score_with_silero(model, frame)?;
291	        let res = self.push_scored_frame(frame, score);
292	        let dt_ms = t0.elapsed().as_millis() as u64;
293	
294	        // Accumulate compute time only for frames that are part of an utterance.
295	        // If this frame starts an utterance, it should count.
296	        if was_in_speech || self.in_speech {
297	            self.cur_vad_compute_ms = self.cur_vad_compute_ms.saturating_add(dt_ms);
298	        }
299	
300	        Ok(res)
301	    }
302	
303	    /// Force-cut the current utterance (if any) and return it as a job.
304	    ///
305	    /// This is used when the upstream audio source stops abruptly (e.g. PTT released),
306	    /// which would otherwise prevent VAD from ever observing trailing silence and ending
307	    /// the utterance naturally.
308	    pub fn force_flush(&mut self) -> Option<UtteranceJob> {
309	        if !self.in_speech {
310	            // Nothing in progress; reset any partial start state.
311	            self.start_run_frames = 0;
312	            self.silence_run_frames = 0;
313	            self.pending_silence.clear();
314	            return None;
315	        }
316	
317	        Some(self.finish_current_utterance_with_tail())
318	    }
319	}
