321	#[cfg(test)]
322	mod tests {
323	    use super::*;
324	
325	    fn frame_with(value: f32) -> [f32; FRAME_SAMPLES] {
326	        [value; FRAME_SAMPLES]
327	    }
328	
329	    #[test]
330	    fn min_speech_required_before_starting_utterance() {
331	        let mut cfg = VadConfig::default();
332	        cfg.min_speech_frames = 5;
333	        cfg.preroll_frames = 2;
334	        let mut seg = VadSegmenter::new(cfg.clone());
335	
336	        // 4 frames above start threshold: not enough to commit.
337	        for _ in 0..4 {
338	            assert!(seg
339	                .push_scored_frame(&frame_with(0.1), cfg.start_threshold + 0.01)
340	                .is_none());
341	        }
342	
343	        // 5th frame commits start; still no job emitted.
344	        assert!(seg
345	            .push_scored_frame(&frame_with(0.2), cfg.start_threshold + 0.01)
346	            .is_none());
347	        assert!(seg.in_speech, "must be in_speech after min_speech_frames");
348	    }
349	
350	    #[test]
351	    fn end_requires_silence_and_includes_only_tail_not_full_silence() {
352	        let mut cfg = VadConfig::default();
353	        cfg.preroll_frames = 2;
354	        cfg.tail_frames = 2;
355	        cfg.min_speech_frames = 1;
356	        cfg.end_silence_frames = 4;
357	        let mut seg = VadSegmenter::new(cfg.clone());
358	
359	        // Start speech immediately.
360	        assert!(seg
361	            .push_scored_frame(&frame_with(1.0), cfg.start_threshold + 0.1)
362	            .is_none());
363	
364	        // Continue speech for 2 frames.
365	        assert!(seg
366	            .push_scored_frame(&frame_with(1.0), cfg.stop_threshold + 0.1)
367	            .is_none());
368	        assert!(seg
369	            .push_scored_frame(&frame_with(1.0), cfg.stop_threshold + 0.1)
370	            .is_none());
371	
372	        // Now provide 4 silent frames: end triggers on the 4th.
373	        assert!(seg
374	            .push_scored_frame(&frame_with(0.0), cfg.stop_threshold - 0.1)
375	            .is_none());
376	        assert!(seg
377	            .push_scored_frame(&frame_with(0.0), cfg.stop_threshold - 0.1)
378	            .is_none());
379	        assert!(seg
380	            .push_scored_frame(&frame_with(0.0), cfg.stop_threshold - 0.1)
381	            .is_none());
382	        let job = seg
383	            .push_scored_frame(&frame_with(0.0), cfg.stop_threshold - 0.1)
384	            .expect("must emit job on end");
385	
386	        // Tail is 2 frames; we should not include all 4 silent frames.
387	        // job.audio contains preroll + speech frames + tail frames (silence).
388	        let samples_per_frame = FRAME_SAMPLES;
389	        let min_expected_frames = cfg.preroll_frames + 3; // 1 start + 2 speech
390	        let max_expected_frames = min_expected_frames + cfg.tail_frames;
391	        let got_frames = job.audio.len() / samples_per_frame;
392	        assert!(
393	            got_frames <= max_expected_frames,
394	            "should include at most tail silence, got frames={got_frames}, max={max_expected_frames}"
395	        );
396	    }
397	
398	    #[test]
399	    fn max_length_forces_cut() {
400	        let mut cfg = VadConfig::default();
401	        cfg.min_speech_frames = 1;
402	        cfg.max_utterance_frames = 3;
403	        cfg.end_silence_frames = 100; // won't end naturally in this test
404	        cfg.preroll_frames = 0;
405	        cfg.tail_frames = 0;
406	        let mut seg = VadSegmenter::new(cfg.clone());
407	
408	        // Start.
409	        assert!(seg
410	            .push_scored_frame(&frame_with(1.0), cfg.start_threshold + 0.1)
411	            .is_none());
412	
413	        // Push frames until cap exceeded; should force-cut.
414	        assert!(seg
415	            .push_scored_frame(&frame_with(1.0), cfg.stop_threshold + 0.1)
416	            .is_none());
417	        assert!(seg
418	            .push_scored_frame(&frame_with(1.0), cfg.stop_threshold + 0.1)
419	            .is_none());
420	        let job = seg
421	            .push_scored_frame(&frame_with(1.0), cfg.stop_threshold + 0.1)
422	            .expect("must force-cut at cap");
423	
424	        let got_frames = job.audio.len() / FRAME_SAMPLES;
425	        assert!(
426	            got_frames <= cfg.max_utterance_frames,
427	            "forced cut must not exceed cap"
428	        );
429	    }
430	}
