140	#[derive(Debug, Clone, Deserialize, Serialize)]
141	#[serde(deny_unknown_fields)]
142	pub struct VadConfig {
143	    #[serde(default = "default_vad_start_threshold")]
144	    pub start_threshold: f32,
145	    #[serde(default = "default_vad_stop_threshold")]
146	    pub stop_threshold: f32,
147	    #[serde(default = "default_min_speech_ms")]
148	    pub min_speech_ms: u64,
149	    #[serde(default = "default_end_silence_ms")]
150	    pub end_silence_ms: u64,
151	    #[serde(default = "default_preroll_ms")]
152	    pub preroll_ms: u64,
