1	//! Speech-to-text (whisper.cpp via `whisper-rs`) running on a dedicated OS thread.
2	//!
3	//! Constraints:
4	//! - Must run on a dedicated blocking OS thread (never Tokio).
5	//! - Model is loaded from a local path at startup (no network).
6	//! - Inference is CPU-only; final-only output (no streaming partials by default).
7	//! - Input queue is bounded with drop-oldest semantics; send path must not block.
8	
9	use anyhow::{anyhow, Context, Result};
10	use crossbeam_channel::{Receiver, Sender};
11	use std::path::{Path, PathBuf};
12	use std::time::Duration;
13	use tokio_util::sync::CancellationToken;
14	
15	use crate::vad::{try_send_drop_oldest, UtteranceJob};
16	
17	#[derive(Debug)]
18	pub enum SttMsg {
19	    Job(UtteranceJob),
20	    Shutdown,
21	}
22	
23	#[derive(Debug, Clone)]
24	pub struct SttResult {
25	    pub utterance_id: u64,
26	    pub text: String,
27	    pub audio_ms: u64,
28	    pub stt_ms: u64,
29	    pub timings: crate::pipeline::timing::UtteranceTimings,
30	    pub start_frame_idx: u64,
31	    pub end_frame_idx: u64,
32	}
33	
34	#[derive(Debug)]
35	pub struct SttService {
36	    model_path: PathBuf,
37	    initial_prompt: Option<String>,
38	    job_tx: Sender<SttMsg>,
39	    job_rx: Receiver<SttMsg>,
40	    result_tx: Sender<SttResult>,
41	    pub result_rx: Receiver<SttResult>,
42	    shutdown: CancellationToken,
43	    handle: Option<std::thread::JoinHandle<()>>,
44	}
45	
46	/// Cloneable submit-only handle for the STT bounded queue.
47	#[derive(Debug, Clone)]
48	pub struct SttSubmitter {
49	    job_tx: Sender<SttMsg>,
50	    job_rx: Receiver<SttMsg>,
51	}
52	
53	impl SttSubmitter {
54	    /// Non-blocking submit. If queue is full, drops the oldest pending job (D-03).
55	    pub fn try_submit(&self, job: UtteranceJob) -> Result<()> {
56	        try_send_drop_oldest(&self.job_tx, &self.job_rx, SttMsg::Job(job))
57	            .map_err(|_| anyhow!("STT job queue is disconnected"))
58	    }
59	}
60	
61	impl SttService {
62	    pub fn submitter(&self) -> SttSubmitter {
63	        SttSubmitter {
64	            job_tx: self.job_tx.clone(),
65	            job_rx: self.job_rx.clone(),
66	        }
67	    }
68	
69	    /// Convenience for single-owner use: submit directly via the service.
70	    pub fn try_submit(&self, job: UtteranceJob) -> Result<()> {
71	        self.submitter().try_submit(job)
72	    }
73	
74	    pub fn result_receiver(&self) -> Receiver<SttResult> {
75	        self.result_rx.clone()
76	    }
77	
78	    /// Create the STT service and preload the model from `model_path`.
79	    ///
80	    /// This function spawns a long-lived `std::thread` and returns immediately.
81	    pub fn new(
82	        model_path: impl AsRef<Path>,
83	        initial_prompt: Option<String>,
84	        shutdown: CancellationToken,
85	    ) -> Result<Self> {
86	        let model_path = model_path.as_ref().to_path_buf();
87	        ensure_model_exists(&model_path)?;
88	
89	        // Bounded queue: must not allow unbounded growth (T-02-07).
90	        let (job_tx, job_rx) = crossbeam_channel::bounded::<SttMsg>(4);
91	        let (result_tx, result_rx) = crossbeam_channel::bounded::<SttResult>(8);
92	
93	        Ok(Self {
94	            model_path,
95	            initial_prompt,
96	            job_tx,
97	            job_rx,
98	            result_tx,
99	            result_rx,
100	            shutdown,
101	            handle: None,
102	        })
103	    }
104	
105	    pub fn spawn(mut self) -> Result<Self> {
106	        let job_rx = self.job_rx.clone();
107	        let result_tx = self.result_tx.clone();
108	        let result_rx_for_drop = self.result_rx.clone();
109	        let shutdown = self.shutdown.clone();
110	
111	        let model_path = self.model_path.clone();
112	        let initial_prompt = self.initial_prompt.clone();
113	
114	        let handle = std::thread::spawn(move || {
115	            tracing::info!("STT thread started");
116	
117	            #[cfg(not(feature = "stt"))]
118	            {
119	                let _ = model_path; // silence unused warning
120	                let _ = (&job_rx, &result_tx, &result_rx_for_drop, &shutdown);
121	                tracing::error!("STT is enabled but binary was built without `--features stt`");
122	                tracing::info!("STT thread stopped");
123	                return;
124	            }
125	
126	            #[cfg(feature = "stt")]
127	            {
128	                use whisper_rs::{
129	                    FullParams, SamplingStrategy, WhisperContext, WhisperContextParameters,
130	                };
131	                use std::time::Instant;
132	
133	                // Load model once at startup (D-15).
134	                let start_load = Instant::now();
135	                let ctx = match WhisperContext::new_with_params(
136	                    model_path.to_string_lossy().to_string(),
137	                    WhisperContextParameters::default(),
138	                ) {
139	                    Ok(c) => c,
140	                    Err(e) => {
141	                        tracing::error!("Failed to load whisper model: {e}");
142	                        return;
143	                    }
144	                };
145	                tracing::info!("Whisper model loaded in {}ms", start_load.elapsed().as_millis());
146	
147	                let base_params = FullParams::new(SamplingStrategy::Greedy { best_of: 1 });
148	
149	                // Create state once and reuse across jobs — avoids heap fragmentation from
150	                // repeated 190 MB alloc/free cycles that cause bad_alloc after ~N utterances.
151	                let mut state = match ctx.create_state() {
152	                    Ok(s) => s,
153	                    Err(e) => {
154	                        tracing::error!("Failed to create whisper state: {e}");
155	                        return;
156	                    }
157	                };
158	
159	                loop {
160	                    if shutdown.is_cancelled() {
161	                        break;
162	                    }
163	
164	                    match job_rx.recv_timeout(Duration::from_millis(50)) {
165	                        Ok(SttMsg::Shutdown) => break,
166	                        Ok(SttMsg::Job(job)) => {
167	                            let stt_start = Instant::now();
168	
169	                            let mut params = base_params.clone();
170	                            params.set_print_special(false);
171	                            params.set_print_progress(false);
172	                            params.set_print_realtime(false);
173	                            params.set_print_timestamps(false);
174	                            params.set_translate(false);
175	                            if let Some(ref prompt) = initial_prompt {
176	                                params.set_initial_prompt(prompt);
177	                            }
178	
179	                            if let Err(e) = state.full(params, &job.audio) {
180	                                tracing::warn!(utterance_id = job.utterance_id, "whisper full() failed: {e}");
181	                                continue;
182	                            }
183	
184	                            let n = state.full_n_segments();
185	
186	                            let mut text = String::new();
187	                            for i in 0..n {
188	                                if let Some(seg) = state.get_segment(i) {
189	                                    let seg = seg
190	                                        .to_str_lossy()
191	                                        .unwrap_or_default();
192	                                    let seg = seg.trim();
193	                                    if !seg.is_empty() {
194	                                        text.push_str(seg);
195	                                        if !text.ends_with(' ') {
196	                                            text.push(' ');
197	                                        }
198	                                    }
199	                                }
200	                            }
201	                            let text = text.trim().to_string();
202	
203	                            let stt_ms = stt_start.elapsed().as_millis() as u64;
204	                            let audio_ms = ((job.audio.len() as u64) * 1000) / (crate::vad::SAMPLE_RATE_HZ as u64);
205	
206	                            let mut timings = job.timings;
207	                            timings.mark_stt_done();
208	
209	                            let result = SttResult {
210	                                utterance_id: job.utterance_id,
211	                                text,
212	                                audio_ms,
213	                                stt_ms,
214	                                timings,
215	                                start_frame_idx: job.start_frame_idx,
216	                                end_frame_idx: job.end_frame_idx,
217	                            };
218	
219	                            // Non-blocking bounded send with drop-oldest behavior.
220	                            if try_send_drop_oldest(&result_tx, &result_rx_for_drop, result).is_err() {
221	                                break;
222	                            }
223	                        }
224	                        Err(crossbeam_channel::RecvTimeoutError::Timeout) => continue,
225	                        Err(crossbeam_channel::RecvTimeoutError::Disconnected) => break,
226	                    }
227	                }
228	
229	                tracing::info!("STT thread stopped");
230	            }
231	        });
232	
233	        self.handle = Some(handle);
234	        Ok(self)
235	    }
236	
237	    pub fn request_shutdown(&self) {
238	        let _ = self.job_tx.try_send(SttMsg::Shutdown);
239	    }
240	
241	    pub fn join_best_effort(&mut self, timeout: Duration) {
242	        if let Some(handle) = self.handle.take() {
243	            let joiner = std::thread::spawn(move || handle.join());
244	            std::thread::sleep(timeout);
245	            drop(joiner);
246	        }
247	    }
248	}
249	
250	fn ensure_model_exists(path: &Path) -> Result<()> {
251	    std::fs::metadata(path).with_context(|| {
252	        format!(
253	            "STT model file missing: {}\n\
254	             Provide a local whisper.cpp model file path (e.g. tiny.en.bin).",
255	            path.display()
256	        )
257	    })?;
258	    Ok(())
259	}
