135	                Err(crossbeam_channel::RecvTimeoutError::Timeout) => continue,
136	                Err(crossbeam_channel::RecvTimeoutError::Disconnected) => break,
137	            }
138	        }
139	        tracing::info!("Dispatcher thread stopped");
140	    });
141	
142	    let jsonl_verbosity = match config.pipeline.verbosity {
143	        PipelineVerbosity::Summary => JsonlVerbosity::SummaryOnly,
144	        PipelineVerbosity::Stages => JsonlVerbosity::Stages,
145	    };
146	
147	    let output_shutdown = shutdown.clone();
148	    let output = std::thread::spawn(move || {
149	        let stdout = std::io::stdout();
150	        let mut w = JsonlWriter::new(stdout.lock(), jsonl_verbosity);
151	
152	        // Emit a startup event to force a flush and verify stdout is working (D-19).
153	        if let Err(e) = w.write_event(&crate::pipeline::jsonl::JsonlEvent::Status {
154	            message: "pipeline_started",
155	            mono_ms: 0,
156	        }) {
157	            tracing::error!("Failed to write startup JSONL: {e}");
158	        }
159	
160	        while !output_shutdown.is_cancelled() {
161	            match out_rx.recv_timeout(Duration::from_millis(50)) {
162	                Ok(OutputMsg::Utterance(mut r)) => {
163	                    r.timings.mark_output_done();
164	                    if let Err(e) = w.write_utterance(
165	                        r.utterance_id,
166	                        &r.text,
167	                        r.audio_ms,
168	                        r.stt_ms,
169	                        r.timings,
170	                        r.start_frame_idx,
171	                        r.end_frame_idx,
172	                    ) {
173	                        tracing::error!("Failed to write stdout JSONL: {e}");
174	                    }
175	                }
176	                Ok(OutputMsg::Dispatched { utterance_id, macro_id, score }) => {
177	                    if let Err(e) = w.write_dispatch(utterance_id, &macro_id, score) {
178	                        tracing::error!("Failed to write dispatch JSONL: {e}");
179	                    }
180	                }
181	                Ok(OutputMsg::NoMatch { utterance_id, transcript }) => {
182	                    if let Err(e) = w.write_no_match(utterance_id, &transcript) {
183	                        tracing::error!("Failed to write no_match JSONL: {e}");
184	                    }
185	                }
186	                Err(crossbeam_channel::RecvTimeoutError::Timeout) => continue,
187	                Err(crossbeam_channel::RecvTimeoutError::Disconnected) => break,
188	            }
189	        }
190	    });
191	
192	    // STT service (optional, feature-gated) is created before threads (fail-fast).
193	    let stt: Option<SttService> = if config.stt.enabled {
194	        let model_path = config
195	            .stt
196	            .model_path
197	            .as_ref()
198	            .context("stt.enabled but stt.model_path is not set")?;
199	
200	        #[cfg(not(feature = "stt"))]
201	        {
202	            let _ = model_path;
203	            return Err(anyhow::anyhow!(
204	                "Config enables STT, but this build was compiled without `--features stt`."
205	            ));
206	        }
207	
208	        #[cfg(feature = "stt")]
209	        {
210	            Some(
211	                SttService::new(model_path, config.stt.initial_prompt.clone(), shutdown.clone())
212	                    .context("create STT service")?
213	                    .spawn()
214	                    .context("spawn STT thread")?,
215	            )
216	        }
217	    } else {
218	        None
219	    };
220	
221	    let stt_submit = stt.as_ref().map(|s| s.submitter());
222	    let stt_results = stt.as_ref().map(|s| s.result_receiver());
223	
224	    // Wake word (optional). Construct before pipeline loop (fail-fast).
225	    let wake = if config.wake.enabled {
226	        Some(WakeWord::new(&config.wake).context("init wake word")?)
227	    } else {
228	        None
229	    };
230	
231	    // VAD model is required for utterance segmentation (CPU-only baseline, D-16).
232	    //
233	    // IMPORTANT: `ort` (ONNX Runtime) can panic at runtime if `libonnxruntime.so`
234	    // is not discoverable. Convert that into a normal, actionable startup error
235	    // instead of crashing the process.
236	    let start_vad = std::time::Instant::now();
237	    let mut silero = std::panic::catch_unwind(|| {
238	        silero_vad_rust::silero_vad::model::load_silero_vad_with_options(
