246	        anyhow::anyhow!(
247	            "Failed to load Silero VAD: ONNX Runtime could not be loaded.\n\
248	             Fix: install ONNX Runtime so `libonnxruntime.so` is in your library path, or set ORT_DYLIB_PATH to the full path of `libonnxruntime.so`.\n\
249	             Example (Arch/CachyOS): `sudo pacman -S onnxruntime`"
250	        )
251	    })?
252	    .context("load silero VAD model")?;
253	    tracing::info!("Silero VAD loaded in {}ms", start_vad.elapsed().as_millis());
254	
255	    // NOTE: the CPAL stream guard is intentionally NOT in this function — the
256	    // caller (main) keeps it alive. We only own the ringbuf consumer end.
257	    let pipeline_shutdown = shutdown.clone();
258	
