44	fn try_main() -> Result<(), DynError> {
45	    println!("cargo:rerun-if-env-changed=SHERPA_ONNX_LIB_DIR");
46	    println!("cargo:rerun-if-env-changed=SHERPA_ONNX_ARCHIVE_DIR");
47	    println!("cargo:rerun-if-env-changed=DOCS_RS");
48	
49	    if env::var_os("DOCS_RS").is_some() {
50	        // docs.rs sets DOCS_RS=1; skip downloading/linking native libraries
51	        // so that `cargo doc` can succeed without the real C artifacts.
52	        return Ok(());
53	    }
54	
55	    let target_os = env::var("CARGO_CFG_TARGET_OS")?;
56	    let target_arch = env::var("CARGO_CFG_TARGET_ARCH")?;
57	    let link_mode = resolve_link_mode()?;
58	    let lib_dir = resolve_lib_dir(link_mode, &target_os, &target_arch)?;
59	
60	    println!("cargo:rustc-link-search=native={}", lib_dir.display());
61	
62	    if link_mode == LinkMode::Shared && matches!(target_os.as_str(), "linux" | "macos") {
63	        println!("cargo:rustc-link-arg=-Wl,-rpath,{}", lib_dir.display());
64	        emit_relative_rpath(&target_os);
65	        copy_unix_runtime_libs(&lib_dir, &target_os)?;
66	    }
67	
68	    if link_mode == LinkMode::Shared && target_os == "windows" {
69	        copy_windows_runtime_dlls(&lib_dir)?;
70	    }
71	
72	    match link_mode {
73	        LinkMode::Static => emit_static_link_directives(&target_os),
74	        LinkMode::Shared => emit_shared_link_directives(),
75	    }
76	
77	    Ok(())
78	}
