80	fn resolve_link_mode() -> Result<LinkMode, DynError> {
81	    let static_enabled = env::var_os("CARGO_FEATURE_STATIC").is_some();
82	    let shared_enabled = env::var_os("CARGO_FEATURE_SHARED").is_some();
83	
84	    if static_enabled && shared_enabled {
85	        return Err("Features `static` and `shared` cannot be enabled at the same time".into());
86	    }
87	
88	    if shared_enabled {
89	        Ok(LinkMode::Shared)
90	    } else {
91	        Ok(LinkMode::Static)
92	    }
93	}
