95	fn resolve_lib_dir(
96	    link_mode: LinkMode,
97	    target_os: &str,
98	    target_arch: &str,
99	) -> Result<PathBuf, DynError> {
100	    if let Some(path) = env::var_os("SHERPA_ONNX_LIB_DIR") {
101	        let path = PathBuf::from(path);
102	        if !path.is_dir() {
103	            return Err(format!(
104	                "SHERPA_ONNX_LIB_DIR does not exist or is not a directory: {}",
105	                path.display()
106	            )
107	            .into());
108	        }
109	        return Ok(path);
110	    }
111	
112	    download_prebuilt_libs(link_mode, target_os, target_arch)
113	}
114	
115	fn download_prebuilt_libs(
116	    link_mode: LinkMode,
117	    target_os: &str,
118	    target_arch: &str,
119	) -> Result<PathBuf, DynError> {
120	    let archive_name = archive_name(link_mode, target_os, target_arch)?;
121	    let archive_stem = archive_name.trim_end_matches(".tar.bz2");
122	
123	    let out_dir = PathBuf::from(env::var("OUT_DIR")?);
124	    let cache_root = target_dir_from_out_dir(&out_dir)?.join("sherpa-onnx-prebuilt");
125	    let extracted_dir = cache_root.join(archive_stem);
126	    let lib_dir = extracted_dir.join("lib");
127	
128	    if lib_dir.is_dir() {
129	        return Ok(lib_dir);
130	    }
131	
132	    fs::create_dir_all(&cache_root)?;
133	
134	    let archive_path = cache_root.join(&archive_name);
135	    if !archive_path.is_file() {
136	        if let Some(local_archive_dir) = env::var_os("SHERPA_ONNX_ARCHIVE_DIR") {
137	            let local_archive_path = PathBuf::from(local_archive_dir).join(&archive_name);
138	            if !local_archive_path.is_file() {
139	                return Err(format!(
140	                    "SHERPA_ONNX_ARCHIVE_DIR does not contain expected archive: {}",
141	                    local_archive_path.display()
142	                )
143	                .into());
144	            }
145	
146	            copy_file_atomically(&local_archive_path, &archive_path)?;
147	        } else {
148	            let version = env!("CARGO_PKG_VERSION");
149	            let url = format!("{RELEASE_BASE_URL}/v{version}/{archive_name}");
150	            eprintln!("Downloading sherpa-onnx libs from {url}");
151	
152	            let response = ureq::builder()
153	                .try_proxy_from_env(true)
154	                .build()
155	                .get(&url)
156	                .call()
157	                .map_err(|e| format!("Failed to download sherpa-onnx archive from {url}: {e}"))?;
158	            let mut reader = response.into_reader();
159	            write_reader_atomically(&mut reader, &archive_path)?;
160	        }
161	    }
162	
163	    if extracted_dir.exists() {
164	        fs::remove_dir_all(&extracted_dir)?;
165	    }
166	
167	    let unpack_result: Result<(), DynError> = (|| {
168	        let tar_file = File::open(&archive_path)?;
169	        let decoder = BzDecoder::new(tar_file);
170	        let mut archive = Archive::new(decoder);
171	        archive.unpack(&cache_root)?;
172	        Ok(())
173	    })();
174	    if let Err(err) = unpack_result {
175	        let _ = fs::remove_file(&archive_path);
176	        let _ = fs::remove_dir_all(&extracted_dir);
177	        return Err(format!(
178	            "Failed to unpack cached archive {}: {err}",
179	            archive_path.display()
180	        )
181	        .into());
182	    }
183	
184	    if !lib_dir.is_dir() {
185	        return Err(format!(
186	            "Downloaded archive did not contain a lib directory: {}",
187	            lib_dir.display()
188	        )
189	        .into());
190	    }
191	
192	    eprintln!("Downloaded sherpa-onnx libs to {}", extracted_dir.display());
193	
194	    Ok(lib_dir)
195	}
