211	            format!("sherpa-onnx-v{version}-osx-x64-static-lib.tar.bz2")
212	        }
213	        (LinkMode::Static, "macos", "aarch64") => {
214	            format!("sherpa-onnx-v{version}-osx-arm64-static-lib.tar.bz2")
215	        }
216	        (LinkMode::Static, "windows", "x86_64") => {
217	            format!("sherpa-onnx-v{version}-win-x64-static-MT-Release-lib.tar.bz2")
218	        }
219	        (LinkMode::Shared, "linux", "x86_64") => {
220	            format!("sherpa-onnx-v{version}-linux-x64-shared-lib.tar.bz2")
221	        }
222	        (LinkMode::Shared, "linux", "aarch64") => {
223	            format!("sherpa-onnx-v{version}-linux-aarch64-shared-cpu-lib.tar.bz2")
224	        }
225	        (LinkMode::Shared, "macos", "x86_64") => {
226	            format!("sherpa-onnx-v{version}-osx-x64-shared-lib.tar.bz2")
227	        }
228	        (LinkMode::Shared, "macos", "aarch64") => {
229	            format!("sherpa-onnx-v{version}-osx-arm64-shared-lib.tar.bz2")
230	        }
231	        (LinkMode::Shared, "windows", "x86_64") => {
232	            format!("sherpa-onnx-v{version}-win-x64-shared-MT-Release-lib.tar.bz2")
