268	fn target_dir_from_out_dir(out_dir: &Path) -> Result<PathBuf, DynError> {
269	    if let Ok(explicit_target_dir) = env::var("CARGO_TARGET_DIR") {
270	        return Ok(PathBuf::from(explicit_target_dir));
271	    }
