308	fn copy_unix_runtime_libs(lib_dir: &Path, target_os: &str) -> Result<(), DynError> {
309	    let runtime_libs: Vec<PathBuf> = fs::read_dir(lib_dir)?
310	        .filter_map(|entry| entry.ok().map(|e| e.path()))
311	        .filter(|path| {
312	            path.file_name()
313	                .and_then(OsStr::to_str)
314	                .map(|name| match target_os {
315	                    "linux" => name.contains(".so"),
316	                    "macos" => name.ends_with(".dylib"),
317	                    _ => false,
318	                })
319	                .unwrap_or(false)
320	        })
321	        .collect();
322	
323	    if runtime_libs.is_empty() {
324	        return Err(format!(
325	            "No shared runtime libraries found in {}",
326	            lib_dir.display()
327	        )
328	        .into());
329	    }
330	
331	    let mut copy_plan = Vec::<(PathBuf, OsString)>::new();
332	    let mut planned_names = HashSet::<OsString>::new();
333	
334	    for lib in runtime_libs {
335	        if !lib.exists() {
336	            continue;
337	        }
338	
339	        let lib_name = lib
340	            .file_name()
341	            .ok_or_else(|| format!("Invalid runtime library path: {}", lib.display()))?
342	            .to_os_string();
343	
344	        let source = fs::canonicalize(&lib).unwrap_or(lib.clone());
345	        if planned_names.insert(lib_name.clone()) {
346	            copy_plan.push((source.clone(), lib_name));
347	        }
348	
349	        if let Some(source_name) = source.file_name() {
350	            let source_name = source_name.to_os_string();
351	            if planned_names.insert(source_name.clone()) {
352	                copy_plan.push((source.clone(), source_name));
353	            }
354	        }
355	    }
356	
357	    if copy_plan.is_empty() {
358	        return Err(format!(
359	            "No usable shared runtime libraries found in {}",
360	            lib_dir.display()
361	        )
362	        .into());
363	    }
364	
365	    for dest_dir in profile_output_dirs()? {
366	        fs::create_dir_all(&dest_dir)?;
367	        for (source, dest_name) in &copy_plan {
368	            let dest = dest_dir.join(dest_name);
369	            fs::copy(source, &dest)?;
370	        }
371	    }
372	
373	    Ok(())
374	}
