376	fn temp_path_for(path: &Path) -> PathBuf {
377	    let mut temp_name = path
378	        .file_name()
379	        .map(OsStr::to_os_string)
380	        .unwrap_or_else(|| OsString::from("tmp"));
381	    temp_name.push(".part");
382	    path.with_file_name(temp_name)
383	}
384	
385	fn copy_file_atomically(src: &Path, dst: &Path) -> Result<(), DynError> {
386	    let temp_path = temp_path_for(dst);
387	    if temp_path.exists() {
388	        let _ = fs::remove_file(&temp_path);
389	    }
390	    fs::copy(src, &temp_path)?;
391	    fs::rename(&temp_path, dst)?;
392	    Ok(())
393	}
394	
395	fn write_reader_atomically(reader: &mut dyn io::Read, dst: &Path) -> Result<(), DynError> {
396	    let temp_path = temp_path_for(dst);
397	    if temp_path.exists() {
398	        let _ = fs::remove_file(&temp_path);
399	    }
400	
401	    {
402	        let mut file = File::create(&temp_path)?;
403	        io::copy(reader, &mut file)?;
404	        file.sync_all()?;
405	    }
406	
407	    fs::rename(&temp_path, dst)?;
408	    Ok(())
409	}
