411	fn copy_windows_runtime_dlls(lib_dir: &Path) -> Result<(), DynError> {
412	    let dlls: Vec<PathBuf> = fs::read_dir(lib_dir)?
413	        .filter_map(|entry| entry.ok().map(|e| e.path()))
414	        .filter(|path| path.extension() == Some(OsStr::new("dll")))
415	        .collect();
416	
417	    if dlls.is_empty() {
418	        println!(
419	            "cargo:warning=No runtime DLLs found in {}",
420	            lib_dir.display()
421	        );
422	        return Ok(());
423	    }
424	
425	    let [profile_dir, examples_dir] = profile_output_dirs()?;
426	    for dest_dir in [profile_dir.clone(), examples_dir] {
427	        fs::create_dir_all(&dest_dir)?;
428	        for dll in &dlls {
429	            let dest = dest_dir.join(
430	                dll.file_name()
431	                    .ok_or_else(|| format!("Invalid DLL path: {}", dll.display()))?,
432	            );
433	            fs::copy(dll, &dest)?;
434	        }
435	    }
436	
437	    println!(
438	        "cargo:warning=Copied Windows runtime DLLs to {} and {}/examples",
439	        profile_dir.display(),
440	        profile_dir.display()
441	    );
442	
443	    Ok(())
444	}
